parameters.jsCode:
// Extract alert fields from Slack messages and filter unprocessed alerts
const alerts = [];

for (const item of $input.all()) {
  const msg = item.json;
  const text = msg.text || '';

  // Skip non-alert messages (look for a splunk link/reference)
  if (!text.toLowerCase().includes('splunk') && !text.toLowerCase().includes('alert')) {
    continue;
  }

  // Extract fields from the Slack message
  const splunkMatch = text.match(/splunk[^\s]*(https?:\/\/[^\s]+|[A-Z_]+\d+)/i);
  const severityMatch = text.match(/severity\s*[:=]\s*(critical|high|medium|low)/i);
  const serviceMatch = text.match(/service\s*[:=]\s*([\w-]+)/i);

  alerts.push({
    json: {
      alert_id: msg.ts || `alert-${Date.now()}`,
      timestamp: msg.ts ? new Date(parseFloat(msg.ts) * 1000).toISOString() : new Date().toISOString(),
      source_service: serviceMatch ? serviceMatch[1] : 'unknown',
      severity: severityMatch ? severityMatch[1].toUpperCase() : 'MEDIUM',
      splunk_query_or_link: splunkMatch ? splunkMatch[1] : text,
      slack_channel: msg.channel || '',
      slack_thread_ts: msg.ts || '',
      raw_text: text
    }
  });
}

if (alerts.length === 0) {
  alerts.push({ json: { _skip: true } });
}

return alerts;

// MOCK: Simulate Splunk log retrieval
// In production, replace with HTTP Request to Splunk API
const alert = $input.first().json;

return [{
  json: {
    ...alert,
    splunk_result: {
      error_signature: `ERR_${alert.source_service.toUpperCase()}_${Date.now().toString(36).slice(-4).toUpperCase()}`,
      error_message: `Simulated error from ${alert.source_service}: connection timeout after 30s`,
      stack_trace_or_log_excerpt: `[${alert.timestamp}] ERROR ${alert.source_service} - TimeoutException: upstream service did not respond within 30000ms\n  at HttpClient.request (client.js:142)\n  at PaymentService.process (payment.js:87)`,
      affected_service: alert.source_service,
      first_seen: alert.timestamp,
      last_seen: alert.timestamp,
      occurrence_count: Math.floor(Math.random() * 50) + 1
    }
  }
}];

// Parse runbook markdown and match against current error
const alert = $input.first().json;
const runbookRaw = $('Fetch Runbook from GitHub').first().json.data || $('Fetch Runbook from GitHub').first().json;
const runbookText = typeof runbookRaw === 'string' ? runbookRaw : JSON.stringify(runbookRaw);

// Parse scenarios from runbook
const scenarioBlocks = runbookText.split(/^## /m).filter(b => b.trim());
const scenarios = [];

for (const block of scenarioBlocks) {
  const idMatch = block.match(/Scenario ID\s*[:=]\s*`?([A-Z_]+\d+)`?/i);
  const patternMatch = block.match(/Match Pattern\s*[:=]\s*`?([^`\n]+)`?/i);
  const impactMatch = block.match(/Impact\s*[:=]\s*`?([^`\n]+)`?/i);

  if (idMatch && patternMatch) {
    scenarios.push({
      scenario_id: idMatch[1],
      match_pattern: patternMatch[1].trim(),
      impact_classification: impactMatch ? impactMatch[1].trim() : 'UNKNOWN',
      raw_block: block
    });
  }
}

// Match current error against known patterns
const errorSig = (alert.splunk_result?.error_message || '').toLowerCase();
let bestMatch = null;
let confidence = 'NO_MATCH';

for (const scenario of scenarios) {
  const pattern = scenario.match_pattern.toLowerCase();
  if (errorSig.includes(pattern) || pattern.includes(errorSig.split(':')[0]?.trim())) {
    bestMatch = scenario;
    confidence = 'MATCHED';
    break;
  }
}

// Check for partial/low confidence match
if (!bestMatch) {
  for (const scenario of scenarios) {
    const keywords = scenario.match_pattern.toLowerCase().split(/[\s_]+/);
    const matchCount = keywords.filter(kw => kw.length > 3 && errorSig.includes(kw)).length;
    if (matchCount >= 2) {
      bestMatch = scenario;
      confidence = 'MATCH_LOW_CONFIDENCE';
      break;
    }
  }
}

return [{
  json: {
    ...alert,
    match_result: confidence,
    matched_scenario: bestMatch,
    total_scenarios_checked: scenarios.length
  }
}];

// Execute matched runbook action (log only for POC - no destructive actions)
const data = $input.first().json;
const scenario = data.matched_scenario;

return [{
  json: {
    action: 'RUNBOOK_EXECUTED',
    scenario_id: scenario.scenario_id,
    alert_id: data.alert_id,
    message: `Matched scenario ${scenario.scenario_id}. Remediation steps would be executed here (POC: logged only).`,
    impact_classification: scenario.impact_classification,
    severity: data.severity,
    timestamp: new Date().toISOString()
  }
}];

// Generate a proposed new scenario from unmatched logs
const data = $input.first().json;
const splunk = data.splunk_result || {};
const ts = new Date().toISOString().slice(0, 10);
const scenarioId = `NEW_${splunk.affected_service?.toUpperCase() || 'SVC'}_${Date.now().toString(36).slice(-3).toUpperCase()}`;

const newScenario = `## ${scenarioId}: ${splunk.error_message || 'Unknown error'}\n\n` +
  `| Field | Value |\n|---|---|\n` +
  `| Scenario ID | \`${scenarioId}\` |\n` +
  `| Title | ${splunk.error_message || 'New scenario'} |\n` +
  `| Match Pattern | \`${splunk.error_signature || 'TBD'}\` |\n` +
  `| Impact | \`USER_IMPACTING\` |\n` +
  `| Remediation Steps | TODO: Define remediation |\n` +
  `| Rollback Steps | TODO: Define rollback |\n` +
  `| Owner Team | TODO: Assign |\n` +
  `| Last Reviewed | ${ts} |\n`;

return [{
  json: {
    ...data,
    new_scenario_id: scenarioId,
    new_scenario_md: newScenario,
    branch_name: `incident/${scenarioId.toLowerCase()}`,
    pr_title: `[Auto] New runbook scenario: ${scenarioId}`,
    pr_body: `Automated PR from incident triage workflow.\n\nAlert ID: ${data.alert_id}\nError: ${splunk.error_message}\nService: ${splunk.affected_service}\nOccurrences: ${splunk.occurrence_count}`
  }
}];

